B.YS=new A.dB("\ud83e\udd16","IA OnExotic","Tu asistente inteligente con acceso a todos los datos de OnExotic en tiempo real.",null)
B.YF=new A.dB("\ud83d\udcac","Qu\xe9 puedes preguntar",'Como CEO puedes preguntar:\n- "\xbfCu\xe1nto stock queda del Drop \xd1?"\n- "\xbfQu\xe9 tareas urgentes hay hoy?"\n- "\xbfQui\xe9n falt\xf3 esta semana?"\n- "Resume el estado de los dise\xf1os"',null)
B.Z2=new A.dB("\ud83d\udd12","Acceso seg\xfan tu rol","Cada rol solo puede consultar su \xe1rea:\n- Dise\xf1adora \u2192 sus dise\xf1os y briefs\n- RRHH \u2192 asistencia y equipo\n- Producci\xf3n \u2192 stock y proveedores\n- CEO \u2192 todo sin l\xedmites",null)
B.YE=new A.dB("\u26a1","Tips para mejores respuestas","S\xe9 espec\xedfico en tus preguntas. Usa las sugerencias r\xe1pidas de abajo para consultas frecuentes. Las respuestas son cortas y directas para ahorrar tiempo.","\xa1Empezar a usar!")
B.Ae=s([B.YS,B.YF,B.Z2,B.YE],t.gG)
B.Yw=new A.pw(B.Ae,null)
B.YH=new A.dB("\ud83d\udc65","Tu equipo OnExotic","Aqu\xed gestionas a todos los miembros del equipo, sus roles, horarios y desempe\xf1o.",null)
B.YU=new A.dB("\u2795","Agregar miembros (solo CEOs)","Toca + para invitar a un nuevo miembro. Llena sus datos: nombre, email, rol y horario. El miembro recibir\xe1 acceso a la app con los permisos de su rol autom\xe1ticamente.",null)
B.YJ=new A.dB("\ud83d\udcca","Seguimiento de asistencia","Cada tarjeta muestra el % de asistencia mensual del miembro.\nVerde = excelente\nAmarillo = regular\nRojo = necesita atenci\xf3n",null)
B.YQ=new A.dB("\ud83d\udcb0","Sistema de bonos","Gestiona los bonos del equipo por trimestre desde la secci\xf3n Bonos. Solo CEOs y RRHH pueden crear y aprobar bonos.","\xa1Entendido!")
B.zH=s([B.YH,B.YU,B.YJ,B.YQ],t.gG)
B.Yx=new A.px(B.zH,null)
B.YO=new A.dB("\ud83d\udce6","Control de inventario","Aqu\xed controlas todo el stock de prendas OnExotic, organizado por drops y tallas.",null)
B.YL=new A.dB("\u2795","Agregar productos","Toca + para agregar un producto nuevo. Puedes agregar el stock de todas las tallas de una sola vez. El SKU se genera autom\xe1ticamente.",null)
B.YX=new A.dB("\ud83d\udea8","Alertas de stock","Cuando el stock baja del m\xednimo configurado, aparece una alerta roja arriba. T\xf3cala para ver qu\xe9 productos necesitas reordenar antes del pr\xf3ximo drop.",null)
B.Z_=new A.dB("\ud83d\uddc2\ufe0f","Organizaci\xf3n por drops","Filtra por drop para ver solo los productos de EXOTIC0, \xd1, Drop 003, etc. Crea nuevos drops con el bot\xf3n + Nuevo drop cuando planifiques una nueva colecci\xf3n.","\xa1Entendido!")
B.A7=s([B.YO,B.YL,B.YX,B.Z_],t.gG)
B.Yy=new A.px(B.A7,null)
B.YM=new A.dB("\ud83d\udccb","Control de asistencia","Aqu\xed registras la asistencia a las reuniones diarias del equipo OnExotic. Las reuniones son todos los d\xedas a las 9:00 AM en el Showroom.",null)
B.YZ=new A.dB("\u2705","C\xf3mo marcar tu asistencia",'Al llegar a la reuni\xf3n, abre esta pantalla y toca "Marcar mi asistencia". Solo puedes hacerlo una vez por reuni\xf3n. Si no marcas, quedas como Pendiente.',null)
B.YK=new A.dB("\ud83d\udc51","Si eres CEO","Como CEO puedes:\n- Crear nuevas reuniones con el bot\xf3n +\n- Ver el estado de todo el equipo\n- Marcar la asistencia de cualquier miembro\n- Ver el historial mensual de asistencia",null)
B.YV=new A.dB("\ud83d\udcc5","Despu\xe9s de la asistencia","Una vez marcada tu asistencia, ve a Tareas para revisar y actualizar las pendientes del d\xeda.","\xa1Entendido!")
B.CO=s([B.YM,B.YZ,B.YK,B.YV],t.gG)
B.Yz=new A.px(B.CO,null)
B.YY=new A.dB("\ud83c\udfa8","Flujo de dise\xf1os","Aqu\xed gestionas todo el proceso creativo de OnExotic, desde la idea hasta el producto final.",null)
B.YP=new A.dB("\ud83d\udcdd","Paso 1: El Brief","Todo empieza con un Brief. El CEO crea un brief con: t\xedtulo, drop asociado, descripci\xf3n, colores de referencia, im\xe1genes e inspiraci\xf3n, tipograf\xeda y fecha l\xedmite de entrega.",null)
B.Z3=new A.dB("\ud83d\udd8c\ufe0f","Paso 2: Proceso y avance","La dise\xf1adora recibe el brief, inicia el proceso y sube avances para que el CEO pueda monitorear el progreso en tiempo real.",null)
B.YR=new A.dB("\ud83d\udc41\ufe0f","Paso 3: Revisi\xf3n","Cuando la dise\xf1adora termina, env\xeda el dise\xf1o a revisi\xf3n. El CEO puede:\n\u2705 Aprobar \u2192 pasa a producci\xf3n\n\u274c Rechazar \u2192 la dise\xf1adora recibe feedback y sube una nueva versi\xf3n.",null)
B.YN=new A.dB("\ud83d\udc55","Paso 4: Producci\xf3n e inventario",'Al aprobar un dise\xf1o, toca "Crear en inventario" para registrar las prendas con sus tallas y cantidades a producir. El dise\xf1o queda vinculado al producto en inventario.',"\xa1Entendido!")
B.zs=s([B.YY,B.YP,B.Z3,B.YR,B.YN],t.gG)
B.YA=new A.px(B.zs,null)
B.YW=new A.dB("\u2705","Gesti\xf3n de tareas","Aqu\xed viven todas las tareas del equipo OnExotic organizadas por \xe1rea y prioridad.",null)
B.Z4=new A.dB("\ud83c\udfaf","Prioridades","Cada tarea tiene una prioridad:\n\ud83d\udd34 Alta \u2192 hacer hoy sin falta\n\ud83d\udfe1 Media \u2192 esta semana\n\ud83d\udfe2 Baja \u2192 cuando haya tiempo\n\nFiltra por \xe1rea: Tech, Dise\xf1o, Marketing, Producci\xf3n, RRHH, Legal.",null)
B.YD=new A.dB("\u2795","Crear tareas (solo CEOs)","Como CEO puedes crear y asignar tareas a cualquier miembro del equipo. Toca el bot\xf3n + para crear una nueva.",null)
B.YT=new A.dB("\ud83d\udd04","Despu\xe9s de las tareas","Si hay dise\xf1os pendientes de revisar, ve a Dise\xf1os. Si hay stock bajo en inventario, actual\xedzalo. Mant\xe9n las tareas al d\xeda para que el equipo funcione bien.","\xa1Entendido!")
