B.YB=new A.px(B.zZ,null)
B.YG=new A.dB("\ud83c\udfe0","Bienvenido a OnExotic","Este es tu centro de control. Desde aqu\xed puedes ver el estado de tu negocio de un vistazo.",null)
B.Z0=new A.dB("\ud83d\udcca","M\xe9tricas en tiempo real","Las 4 cards muestran: stock cr\xedtico, tareas pendientes, asistencia de hoy y d\xedas para el pr\xf3ximo drop. Todo actualizado autom\xe1ticamente.",null)
B.Z1=new A.dB("\ud83d\uddfa\ufe0f","Flujo de trabajo diario","Tu d\xeda en OnExotic sigue este orden:\n1. Marca tu asistencia a la reuni\xf3n diaria\n2. Revisa y actualiza tus tareas del d\xeda\n3. Si eres CEO, revisa los dise\xf1os pendientes\n4. Actualiza el inventario si hay movimientos\n5. Usa el Asistente IA para consultas r\xe1pidas",null)
